import{_ as a,a as i,b as n,c as d,d as l,e as t,f as r,g as o}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as s,o as u,c as m,a2 as p}from"./chunks/framework.DnrXFDHb.js";const I=JSON.parse('{"title":"Federated Distributed Index","description":"","frontmatter":{},"headers":[],"relativePath":"tr-TR/Other/federated-distributed-index.md","filePath":"tr-TR/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),k={name:"tr-TR/Other/federated-distributed-index.md"};function c(y,e,b,h,g,z){return u(),m("div",null,[...e[0]||(e[0]=[p('<h1 id="federated-distributed-index" tabindex="-1">Federated Distributed Index <a class="header-anchor" href="#federated-distributed-index" aria-label="Permalink to &quot;Federated Distributed Index&quot;">​</a></h1><p>Federated distributed index, birden fazla ImgBed sitesinin dosya listelerini birbirleriyle paylaşmasını sağlar.</p><p>Basitçe:</p><ul><li>Sitenizdeki seçili klasörleri başkalarıyla paylaşabilirsiniz.</li><li>Başka bir node&#39;a katılıp o node&#39;un paylaşılan dosya listesini yönetim panelinize senkronize edebilirsiniz.</li><li>Federated files ağırlıklı olarak gezinme, arama ve bağlantı açma içindir. Kendi depolamanıza yeniden yüklenmezler.</li></ul><h2 id="nereden-yapılandırılır" tabindex="-1">Nereden Yapılandırılır? <a class="header-anchor" href="#nereden-yapılandırılır" aria-label="Permalink to &quot;Nereden Yapılandırılır?&quot;">​</a></h2><p>Şurayı açın:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Federated Distributed Index</span></span></code></pre></div><p><img src="'+a+`" alt="Yerel federation node" loading="lazy"></p><p>Sayfada üç sekme vardır:</p><table tabindex="0"><thead><tr><th>Sekme</th><th>Amaç</th></tr></thead><tbody><tr><td>Local Node</td><td>Kendi node&#39;unuzu etkinleştirme, public domain doğrulama, paylaşılan klasörleri seçme ve outbound index güncelleme</td></tr><tr><td>Nodes I Joined</td><td>Katıldığınız diğer ImgBed node&#39;larını yönetme</td></tr><tr><td>Nodes Joining Me</td><td>Sizin node&#39;unuza katılmak isteyenlerin isteklerini yönetme</td></tr></tbody></table><h2 id="ilk-kurulum" tabindex="-1">İlk Kurulum <a class="header-anchor" href="#ilk-kurulum" aria-label="Permalink to &quot;İlk Kurulum&quot;">​</a></h2><ol><li><code>Local Node</code> sekmesini açın.</li><li><code>Enable</code> değerini açın.</li><li><code>Sync folders</code> altında paylaşılacak klasörleri seçin.</li><li><code>Update Outbound Index</code> düğmesine tıklayın.</li><li>ImgBed domain değişikliği algılarsa devam etmeden önce geçerli domain&#39;in doğru olduğunu onaylayın.</li></ol><p>Birden fazla sync folder seçebilirsiniz.</p><p>Sync folder listesi boşsa tüm klasörler paylaşılır.</p><h2 id="local-node" tabindex="-1">Local Node <a class="header-anchor" href="#local-node" aria-label="Permalink to &quot;Local Node&quot;">​</a></h2><h3 id="public-domain" tabindex="-1">Public Domain <a class="header-anchor" href="#public-domain" aria-label="Permalink to &quot;Public Domain&quot;">​</a></h3><p>Public domain, diğer node&#39;ların sizin node&#39;unuza erişmek için kullandığı site URL&#39;sidir.</p><p>ImgBed bunu otomatik algılar. Elle yazmanıza gerek yoktur. Index&#39;i ilk kez güncellediğinizde ImgBed geçerli erişim URL&#39;sinin production domain olup olmadığını onaylamanızı ister.</p><p>Domain&#39;i daha sonra değiştirirseniz index güncellemesi tekrar onay ister.</p><h3 id="sync-folders" tabindex="-1">Sync Folders <a class="header-anchor" href="#sync-folders" aria-label="Permalink to &quot;Sync Folders&quot;">​</a></h3><p>Sync folders, federation node&#39;larıyla hangi dosyaların paylaşılacağını belirler.</p><p>Örneğin yalnızca şunları seçerseniz:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>diğer node&#39;lar yalnızca bu iki dizindeki dosyaları görür.</p><h3 id="update-outbound-index" tabindex="-1">Update Outbound Index <a class="header-anchor" href="#update-outbound-index" aria-label="Permalink to &quot;Update Outbound Index&quot;">​</a></h3><p>Diğer node&#39;ların sizden senkronize edebileceği dosya listesini günceller.</p><p>Şu durumlarda kullanın:</p><ul><li>Federation&#39;ı ilk kez etkinleştirirken.</li><li>Paylaşmak istediğiniz dosyalar yüklediğinizde.</li><li>Sync folders değiştiğinde.</li><li>Public domain değiştiğinde ve onay gerektiğinde.</li></ul><h2 id="nodes-i-joined" tabindex="-1">Nodes I Joined <a class="header-anchor" href="#nodes-i-joined" aria-label="Permalink to &quot;Nodes I Joined&quot;">​</a></h2><p><code>Nodes I Joined</code>, diğer node&#39;lara abone olduğunuz yerdir.</p><p><img src="`+i+'" alt="Nodes I joined" loading="lazy"></p><h3 id="baska-bir-node-a-katılma-istegi-gonderme" tabindex="-1">Başka Bir Node&#39;a Katılma İsteği Gönderme <a class="header-anchor" href="#baska-bir-node-a-katılma-istegi-gonderme" aria-label="Permalink to &quot;Başka Bir Node&#39;a Katılma İsteği Gönderme&quot;">​</a></h3><ol><li>Diğer sahibinden invitation link isteyin.</li><li>Giriş kutusuna yapıştırın.</li><li><code>Request to Join</code> düğmesine tıklayın.</li><li>Diğer sahibin kendi yönetim panelinde isteği onaylamasını bekleyin.</li></ol><p>Onaydan sonra node durumu approved olur.</p><h3 id="update-inbound-index" tabindex="-1">Update Inbound Index <a class="header-anchor" href="#update-inbound-index" aria-label="Permalink to &quot;Update Inbound Index&quot;">​</a></h3><p><code>Update Inbound Index</code>, katıldığınız node&#39;lardan dosya listelerini senkronize eder.</p><p>Şu durumlarda kullanın:</p><ul><li>Diğer sahip isteğinizi yeni onayladıysa.</li><li>Diğer sahip paylaşılan içeriğin güncellendiğini söylediyse.</li><li>Katıldığınız tüm federation dosya listelerini yenilemek istiyorsanız.</li></ul><p>Yalnızca tek bir node&#39;u güncellemek için o node kartında <code>Update Index</code> düğmesine tıklayın.</p><p><img src="'+n+'" alt="Index güncelleme" loading="lazy"></p><h3 id="unsubscribe" tabindex="-1">Unsubscribe <a class="header-anchor" href="#unsubscribe" aria-label="Permalink to &quot;Unsubscribe&quot;">​</a></h3><p>Bir node&#39;u artık senkronize etmek istemiyorsanız <code>Unsubscribe</code> düğmesine tıklayın.</p><p>Abonelikten çıktıktan sonra o node&#39;un federated index&#39;i yerel sitenizden kaldırılır.</p><h2 id="nodes-joining-me" tabindex="-1">Nodes Joining Me <a class="header-anchor" href="#nodes-joining-me" aria-label="Permalink to &quot;Nodes Joining Me&quot;">​</a></h2><p><code>Nodes Joining Me</code>, başkalarından gelen istekleri yönettiğiniz yerdir.</p><p><img src="'+d+'" alt="Nodes joining me" loading="lazy"></p><h3 id="invitation-link-olusturma" tabindex="-1">Invitation Link Oluşturma <a class="header-anchor" href="#invitation-link-olusturma" aria-label="Permalink to &quot;Invitation Link Oluşturma&quot;">​</a></h3><ol><li>Local node&#39;un etkin olduğundan emin olun.</li><li>ImgBed&#39;in public domain&#39;i doğrulaması için en az bir kez <code>Update Outbound Index</code> tıklayın.</li><li><code>Nodes Joining Me</code> sekmesini açın.</li><li><code>Reset Invitation Link</code> düğmesine tıklayın.</li><li>Invitation link&#39;i kopyalayıp diğer sahibine gönderin.</li></ol><p>Invitation link boşsa public domain genellikle henüz doğrulanmamıştır. <code>Local Node</code> sekmesine dönüp <code>Update Outbound Index</code> tıklayın.</p><h3 id="katılma-isteklerini-yonetme" tabindex="-1">Katılma İsteklerini Yönetme <a class="header-anchor" href="#katılma-isteklerini-yonetme" aria-label="Permalink to &quot;Katılma İsteklerini Yönetme&quot;">​</a></h3><p>Birisi istek gönderdiğinde <code>Nodes Joining Me</code> listesinde görünür.</p><table tabindex="0"><thead><tr><th>Eylem</th><th>Anlamı</th></tr></thead><tbody><tr><td>Approve</td><td>Diğer node&#39;un paylaşılan dosya listenizi senkronize etmesine izin verir</td></tr><tr><td>Reject</td><td>Katılma isteğini reddeder</td></tr><tr><td>Delete</td><td>Tamamlanmış kaydı siler</td></tr><tr><td>Check Status</td><td>Diğer tarafın bu ilişkiyi hâlâ koruyup korumadığını kontrol eder</td></tr></tbody></table><p>Onaydan sonra diğer tarafın, paylaşılan dosyalarınız orada görünmeden önce yine <code>Update Inbound Index</code> tıklaması gerekir.</p><p><img src="'+l+'" alt="Davet edilen node&#39;u onaylama" loading="lazy"></p><h2 id="mesajlar" tabindex="-1">Mesajlar <a class="header-anchor" href="#mesajlar" aria-label="Permalink to &quot;Mesajlar&quot;">​</a></h2><p>İlişki onaylandıktan sonra node kartındaki <code>Message</code> düğmesine tıklayın.</p><p>Mesajlar yalnızca federation ilişkisi hakkında iletişim içindir. Dosyaları, etiketleri, dizinleri veya permissions değerlerini değiştirmez.</p><p><img src="'+t+'" alt="Mesajlar" loading="lazy"></p><h2 id="federated-files-goruntuleme" tabindex="-1">Federated Files Görüntüleme <a class="header-anchor" href="#federated-files-goruntuleme" aria-label="Permalink to &quot;Federated Files Görüntüleme&quot;">​</a></h2><p>Senkronizasyon tamamlandıktan sonra yönetim dosya listesine dönün.</p><p>Sayfanın üst kısmında yerel dosyalar ve federated files arasında geçiş yapabilirsiniz. Federated files içinde senkronize içeriği gezebilirsiniz.</p><p>Federated files ağırlıklı olarak görüntüleme, arama, preview ve bağlantı kopyalama içindir. Yerel dosya olmadıkları için kendi sitenizden taşıyamaz, silemez, yeniden etiketleyemez veya yedekleyemezsiniz.</p><p><img src="'+r+'" alt="Yönetimde federated files" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="neden-iliski-kaydı-yok-diye-yeniden-basvurmam-isteniyor" tabindex="-1">Neden İlişki Kaydı Yok Diye Yeniden Başvurmam İsteniyor? <a class="header-anchor" href="#neden-iliski-kaydı-yok-diye-yeniden-basvurmam-isteniyor" aria-label="Permalink to &quot;Neden İlişki Kaydı Yok Diye Yeniden Başvurmam İsteniyor?&quot;">​</a></h3><p>Bu genellikle diğer tarafın sizi silip kaydı kaldırdığı anlamına gelir; ilişki artık bulunamaz. Yeni join request gönderin.</p><p><img src="'+o+'" alt="İlişki kaydı yoksa yeniden başvurma" loading="lazy"></p><h3 id="katıldıktan-sonra-neden-dosya-goremiyorum" tabindex="-1">Katıldıktan Sonra Neden Dosya Göremiyorum? <a class="header-anchor" href="#katıldıktan-sonra-neden-dosya-goremiyorum" aria-label="Permalink to &quot;Katıldıktan Sonra Neden Dosya Göremiyorum?&quot;">​</a></h3><p>Kontrol edin:</p><ol><li>Diğer sahip isteğinizi onayladı.</li><li>Diğer sahip <code>Update Outbound Index</code> tıkladı.</li><li>Siz <code>Update Inbound Index</code> tıkladınız.</li><li>Diğer sahibin sync folders listesi paylaşmak istediği dizinleri içeriyor.</li></ol><h3 id="domain-degisikligi-algılanırsa-ne-yapmalıyım" tabindex="-1">Domain Değişikliği Algılanırsa Ne Yapmalıyım? <a class="header-anchor" href="#domain-degisikligi-algılanırsa-ne-yapmalıyım" aria-label="Permalink to &quot;Domain Değişikliği Algılanırsa Ne Yapmalıyım?&quot;">​</a></h3><p>Yönetim panelini şu anda production domain üzerinden açıyorsanız onaylayıp devam edin.</p><p>Geçici adres kullanıyorsanız iptal edin, yönetim panelini production domain ile yeniden açın ve tekrar deneyin.</p><h3 id="bos-sync-folder-listesi-ne-anlama-gelir" tabindex="-1">Boş Sync Folder Listesi Ne Anlama Gelir? <a class="header-anchor" href="#bos-sync-folder-listesi-ne-anlama-gelir" aria-label="Permalink to &quot;Boş Sync Folder Listesi Ne Anlama Gelir?&quot;">​</a></h3><p>Boş sync folder listesi tüm klasörlerin paylaşıldığı anlamına gelir.</p><p>Yalnızca bazı dizinleri paylaşmak için bu klasörleri elle seçin.</p><h3 id="outbound-ve-inbound-index-guncellemeleri-arasındaki-fark" tabindex="-1">Outbound ve Inbound Index Güncellemeleri Arasındaki Fark <a class="header-anchor" href="#outbound-ve-inbound-index-guncellemeleri-arasındaki-fark" aria-label="Permalink to &quot;Outbound ve Inbound Index Güncellemeleri Arasındaki Fark&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Düğme</th><th>Basit Anlamı</th></tr></thead><tbody><tr><td>Update Outbound Index</td><td>Başkalarının benden senkronize edebileceği şeyi günceller</td></tr><tr><td>Update Inbound Index</td><td>Başkalarından senkronize ettiğim şeyi günceller</td></tr></tbody></table>',78)])])}const q=s(k,[["render",c]]);export{I as __pageData,q as default};
